   1→/**
   2→ * LLM Proxy Acceptance Test Kit
   3→ *
   4→ * Domain-specific helpers for LLM proxy acceptance tests.
   5→ * Extends the shared acceptance-test-kit with proxy-specific
   6→ * workspace setup, request builders, and graph query helpers.
   7→ *
   8→ * Driving ports: HTTP endpoints at /proxy/llm/anthropic/v1/messages
   9→ * and /api/workspaces/:workspaceId/proxy/spend
  10→ */
  11→import { RecordId, type Surreal } from "surrealdb";
  12→import {
  13→  setupAcceptanceSuite,
  14→  createTestUser,
  15→  fetchRaw,
  16→  type AcceptanceTestRuntime,
  17→  type TestUser,
  18→} from "../acceptance-test-kit";
  19→
  20→// Re-export shared helpers
  21→export {
  22→  setupAcceptanceSuite,
  23→  createTestUser,
  24→  fetchRaw,
  25→  type AcceptanceTestRuntime,
  26→  type TestUser,
  27→};
  28→
  29→// ---------------------------------------------------------------------------
  30→// Proxy Request Builders
  31→// ---------------------------------------------------------------------------
  32→
  33→export type ProxyRequestOptions = {
  34→  model: string;
  35→  stream?: boolean;
  36→  maxTokens?: number;
  37→  messages?: Array<{ role: string; content: string }>;
  38→  metadata?: { user_id?: string };
  39→  apiKey?: string;
  40→  workspaceHeader?: string;
  41→  taskHeader?: string;
  42→  agentTypeHeader?: string;
  43→};
  44→
  45→/**
  46→ * Build a proxy request body matching the Anthropic Messages API format.
  47→ */
  48→export function buildProxyRequestBody(options: ProxyRequestOptions): string {
  49→  return JSON.stringify({
  50→    model: options.model,
  51→    max_tokens: options.maxTokens ?? 100,
  52→    stream: options.stream ?? false,
  53→    messages: options.messages ?? [
  54→      { role: "user", content: "Say hello in one word." },
  55→    ],
  56→    ...(options.metadata ? { metadata: options.metadata } : {}),
  57→  });
  58→}
  59→
  60→/**
  61→ * Build headers for a proxy request, including identity headers.
  62→ */
  63→export function buildProxyHeaders(options: ProxyRequestOptions): Record<string, string> {
  64→  const headers: Record<string, string> = {
  65→    "Content-Type": "application/json",
  66→    "anthropic-version": "2023-06-01",
  67→  };
  68→
  69→  if (options.apiKey) {
  70→    headers["x-api-key"] = options.apiKey;
  71→  }
  72→  if (options.workspaceHeader) {
  73→    headers["X-Brain-Workspace"] = options.workspaceHeader;
  74→  }
  75→  if (options.taskHeader) {
  76→    headers["X-Brain-Task"] = options.taskHeader;
  77→  }
  78→  if (options.agentTypeHeader) {
  79→    headers["X-Brain-Agent-Type"] = options.agentTypeHeader;
  80→  }
  81→
  82→  return headers;
  83→}
  84→
  85→/**
  86→ * Send a request through the LLM proxy endpoint.
  87→ * Returns the raw Response for flexible assertion.
  88→ */
  89→export async function sendProxyRequest(
  90→  baseUrl: string,
  91→  options: ProxyRequestOptions,
  92→): Promise<Response> {
  93→  const body = buildProxyRequestBody(options);
  94→  const headers = buildProxyHeaders(options);
  95→
  96→  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages`, {
  97→    method: "POST",
  98→    headers,
  99→    body,
 100→  });
 101→}
