 180→/**
 181→ * Create a workspace record in SurrealDB for proxy testing.
 182→ */
 183→export async function createProxyTestWorkspace(
 184→  surreal: Surreal,
 185→  workspaceId: string,
 186→  options?: { dailyBudget?: number; alertThreshold?: number },
 187→): Promise<string> {
 188→  const workspaceRecord = new RecordId("workspace", workspaceId);
 189→
 190→  const content: Record<string, unknown> = {
 191→    name: `Proxy Test Workspace ${workspaceId}`,
 192→    status: "active",
 193→    onboarding_complete: true,
 194→    onboarding_turn_count: 0,
 195→    onboarding_summary_pending: false,
 196→    onboarding_started_at: new Date(),
 197→    created_at: new Date(),
 198→  };
 199→
 200→  if (options?.dailyBudget !== undefined) {
 201→    content.daily_budget_usd = options.dailyBudget;
 202→  }
 203→
 204→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
 205→    workspace: workspaceRecord,
 206→    content,
 207→  });
 208→
 209→  return workspaceId;
 210→}
