 462→/**
 463→ * Create a model access policy for the proxy.
 464→ */
 465→export async function createModelAccessPolicy(
 466→  surreal: Surreal,
 467→  workspaceId: string,
 468→  options: {
 469→    policyId: string;
 470→    agentType: string;
 471→    allowedModels: string[];
 472→    status?: string;
 473→  },
 474→): Promise<string> {
 475→  const policyRecord = new RecordId("policy", options.policyId);
 476→  const workspaceRecord = new RecordId("workspace", workspaceId);
 477→
 478→  await surreal.query(`CREATE $policy CONTENT $content;`, {
 479→    policy: policyRecord,
 480→    content: {
 481→      title: `Model Access: ${options.agentType}`,
 482→      description: `Controls which models ${options.agentType} can use`,
 483→      status: options.status ?? "active",
 484→      version: 1,
 485→      workspace: workspaceRecord,
 486→      rules: [{
 487→        id: "model_access",
 488→        condition: { field: "agent_type", operator: "eq", value: options.agentType },
 489→        effect: "allow",
 490→        priority: 50,
 491→        params: { allowed_models: options.allowedModels },
 492→      }],
 493→      created_at: new Date(),
 494→    },
 495→  });
 496→
 497→  return options.policyId;
 498→}
