 90→    const valid = (results[0]?.length ?? 0) > 0;
 91→    cache.set(workspaceId, { valid, checkedAt: Date.now() });
 92→    return valid;
 93→  } catch {
 94→    cache.set(workspaceId, { valid: false, checkedAt: Date.now() });
 95→    return false;
 96→  }
 97→}
