 99→// ---------------------------------------------------------------------------
100→// Header Forwarding
101→// ---------------------------------------------------------------------------
102→
103→function buildUpstreamHeaders(request: Request): Headers {
104→  const headers = new Headers();
105→
106→  for (const name of FORWARDED_HEADERS) {
107→    const value = request.headers.get(name);
108→    if (value) headers.set(name, value);
109→  }
110→
111→  const xApiKey = request.headers.get("x-api-key");
112→  const authHeader = request.headers.get("authorization");
113→  if (xApiKey) headers.set("x-api-key", xApiKey);
114→  if (authHeader) headers.set("authorization", authHeader);
115→
116→  return headers;
117→}
