148→// ---------------------------------------------------------------------------
149→// SSE Usage Extraction
150→// ---------------------------------------------------------------------------
151→
152→type StreamContext = {
153→  model?: string;
154→  inputTokens: number;
155→  outputTokens: number;
156→  cacheCreationTokens: number;
157→  cacheReadTokens: number;
158→  stopReason?: string;
159→};
160→
161→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
162→  const lines = buffer.split("\n");
163→  const remainder = lines.pop() ?? "";
164→
165→  for (const line of lines) {
166→    if (!line.startsWith("data: ")) continue;
167→    const data = line.slice(6);
168→    if (data === "[DONE]") continue;
169→
170→    try {
171→      const event = JSON.parse(data);
172→
173→      if (event.type === "message_start" && event.message?.usage) {
174→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
175→        ctx.cacheCreationTokens = event.message.usage.cache_creation_input_tokens ?? 0;
176→        ctx.cacheReadTokens = event.message.usage.cache_read_input_tokens ?? 0;
177→        ctx.model = event.message.model ?? ctx.model;
178→      }
179→
180→      if (event.type === "message_delta") {
181→        if (event.usage?.output_tokens) {
182→          ctx.outputTokens = event.usage.output_tokens;
183→        }
184→        if (event.delta?.stop_reason) {
185→          ctx.stopReason = event.delta.stop_reason;
186→        }
187→      }
188→    } catch {
189→      // partial JSON or non-JSON data line — skip
190→    }
191→  }
192→
193→  return remainder;
194→}
195→
196→// ---------------------------------------------------------------------------
197→// Non-Streaming Usage Extraction
198→// ---------------------------------------------------------------------------
199→
200→type NonStreamingResponse = {
201→  model?: string;
202→  usage?: {
203→    input_tokens?: number;
204→    output_tokens?: number;
205→    cache_creation_input_tokens?: number;
206→    cache_read_input_tokens?: number;
207→  };
208→  stop_reason?: string;
209→};
210→
211→function extractNonStreamingUsage(
212→  responseBody: string,
213→  requestModel: string | undefined,
214→  latencyMs: number,
215→  identity: { workspaceId?: string; taskId?: string },
216→  sessionId?: string,
217→  policyDecision?: PolicyDecisionLog,
218→  conversationId?: string,
219→  injectionResult?: InjectionResult,
220→): TraceData | undefined {
221→  try {
222→    const parsed = JSON.parse(responseBody) as NonStreamingResponse;
223→    if (!parsed.usage) return undefined;
224→
225→    const traceData: TraceData = {
226→      model: parsed.model ?? requestModel ?? "unknown",
227→      inputTokens: parsed.usage.input_tokens ?? 0,
228→      outputTokens: parsed.usage.output_tokens ?? 0,
229→      cacheCreationTokens: parsed.usage.cache_creation_input_tokens ?? 0,
230→      cacheReadTokens: parsed.usage.cache_read_input_tokens ?? 0,
231→      stopReason: parsed.stop_reason,
232→      latencyMs,
233→      workspaceId: identity.workspaceId,
234→      sessionId,
235→      taskId: identity.taskId,
236→      policyDecision,
237→      conversationId,
238→    };
239→
240→    // Add intelligence metadata if injection occurred
241→    if (injectionResult) {
242→      (traceData as any).intelligenceMetadata = buildIntelligenceMetadata(injectionResult);
243→    }
244→
245→    // Capture response content (opaque, per ADR-051)
246→    const responseContent = extractResponseContent(responseBody);
247→    if (responseContent) {
248→      (traceData as any).responseContent = responseContent;
249→    }
250→
251→    return traceData;
252→  } catch {
253→    return undefined;
254→  }
255→}
