257→// ---------------------------------------------------------------------------
258→// Context Candidate Pool Loader (adapter boundary)
259→// ---------------------------------------------------------------------------
260→
261→const DECISION_WEIGHT = 1.0;
262→const LEARNING_WEIGHT = 0.8;
263→const OBSERVATION_WEIGHT = 0.7;
264→
265→async function loadCandidatePool(
266→  surreal: ServerDependencies["surreal"],
267→  workspaceId: string,
268→): Promise<CachedCandidatePool> {
269→  const workspaceRecord = new RecordId("workspace", workspaceId);
270→
271→  type DecisionRow = { id: RecordId; summary: string; embedding?: number[] };
272→  type LearningRow = { id: RecordId; text: string; embedding?: number[] };
273→  type ObservationRow = { id: RecordId; text: string; embedding?: number[] };
274→
275→  const [decisionResults, learningResults, observationResults] = await Promise.all([
276→    surreal.query<[DecisionRow[]]>(
277→      `SELECT id, summary, embedding FROM decision WHERE workspace = $ws AND status = 'confirmed' LIMIT 50;`,
278→      { ws: workspaceRecord },
279→    ),
280→    surreal.query<[LearningRow[]]>(
281→      `SELECT id, text, embedding FROM learning WHERE workspace = $ws AND status = 'active' LIMIT 30;`,
282→      { ws: workspaceRecord },
283→    ),
284→    surreal.query<[ObservationRow[]]>(
285→      `SELECT id, text, embedding FROM observation WHERE workspace = $ws AND status = 'open' AND severity IN ['conflict', 'warning'] LIMIT 20;`,
286→      { ws: workspaceRecord },
287→    ),
288→  ]);
289→
290→  function toCandidates<T extends { id: RecordId; embedding?: number[] }>(
291→    rows: T[],
292→    type: CandidateItem["type"],
293→    weight: number,
294→    textFn: (row: T) => string,
295→  ): CandidateItem[] {
296→    return rows.map((row) => ({
297→      id: (row.id as RecordId).id as string,
298→      type,
299→      text: textFn(row),
300→      weight,
301→      embedding: row.embedding,
302→    }));
303→  }
304→
305→  const decisions = toCandidates(decisionResults[0] ?? [], "decision", DECISION_WEIGHT, (d) => d.summary);
306→  const learnings = toCandidates(learningResults[0] ?? [], "learning", LEARNING_WEIGHT, (l) => l.text);
307→  const observations = toCandidates(observationResults[0] ?? [], "observation", OBSERVATION_WEIGHT, (o) => o.text);
308→
309→  return {
310→    decisions,
311→    learnings,
312→    observations,
313→    populatedAt: Date.now(),
314→  };
315→}
316→
317→// ---------------------------------------------------------------------------
318→// Embedding Helper (adapter boundary)
319→// ---------------------------------------------------------------------------
320→
321→async function embedUserMessage(
322→  embeddingModel: ServerDependencies["embeddingModel"],
323→  embeddingDimension: number,
324→  text: string,
325→): Promise<number[] | undefined> {
326→  try {
327→    const { embed } = await import("ai");
328→    const normalized = text.trim();
329→    if (normalized.length === 0) return undefined;
330→
331→    const result = await embed({
332→      model: embeddingModel,
333→      value: normalized,
334→    });
335→
336→    if (result.embedding.length !== embeddingDimension) return undefined;
337→    return result.embedding;
338→  } catch {
339→    return undefined;
340→  }
341→}
342→
343→// ---------------------------------------------------------------------------
344→// Context Injection Pipeline (orchestrator)
345→// ---------------------------------------------------------------------------
346→
347→type ContextInjectionResult = {
348→  readonly body: string;
349→  readonly injectionResult?: InjectionResult;
350→};
351→
352→async function runContextInjection(
353→  deps: ServerDependencies,
354→  workspaceId: string,
355→  parsedBody: ParsedBody,
356→  originalBody: string,
357→  contextCache: ContextCache,
358→  intelligenceConfig: IntelligenceConfig,
359→): Promise<ContextInjectionResult> {
360→  if (!intelligenceConfig.contextInjectionEnabled) {
361→    return { body: originalBody };
362→  }
363→
364→  // 1. Get or populate candidate pool (with cache)
365→  let pool: CachedCandidatePool;
366→  if (contextCache.has(workspaceId)) {
367→    pool = contextCache.get(workspaceId)!;
368→  } else {
369→    pool = await loadCandidatePool(deps.surreal, workspaceId);
370→    contextCache.set(workspaceId, pool);
371→  }
372→
373→  // 2. Check if pool is empty
374→  const allCandidates: ContextCandidate[] = [
375→    ...pool.decisions,
376→    ...pool.learnings,
377→    ...pool.observations,
378→  ];
379→  if (allCandidates.length === 0) {
380→    return { body: originalBody };
381→  }
382→
383→  // 3. Extract last user message for embedding
384→  const lastUserMessage = [...(parsedBody.messages ?? [])].reverse().find((m) => m.role === "user");
385→  if (!lastUserMessage) {
386→    return { body: originalBody };
387→  }
388→
389→  // 4. Embed last user message
390→  const queryEmbedding = await embedUserMessage(
391→    deps.embeddingModel,
392→    deps.config.embeddingDimension,
393→    lastUserMessage.content,
394→  );
395→
396→  let selectedCandidates;
397→  if (queryEmbedding) {
398→    // 5. Rank candidates by weighted cosine similarity
399→    const ranked = rankCandidates(allCandidates, queryEmbedding);
400→    // 6. Select within token budget
401→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
402→  } else {
403→    // No embedding available -- fall back to all candidates within budget
404→    const ranked = allCandidates.map((c) => ({
405→      id: c.id,
406→      type: c.type,
407→      text: c.text,
408→      score: c.weight,
409→    }));
410→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
411→  }
412→
413→  if (selectedCandidates.length === 0) {
414→    return { body: originalBody };
415→  }
416→
417→  // 7. Build XML block
418→  const brainContextXml = buildBrainContextXml(selectedCandidates);
419→
420→  // 8. Inject into system prompt
421→  const injectionResult = injectBrainContext(parsedBody.system, brainContextXml);
422→
423→  // 9. Build modified request body
424→  const modifiedBody = {
425→    ...parsedBody,
426→    system: injectionResult.system,
427→  };
428→
429→  return {
430→    body: JSON.stringify(modifiedBody),
431→    injectionResult,
432→  };
433→}
434→
435→// ---------------------------------------------------------------------------
436→// Intelligence Metadata Builder (pure)
437→// ---------------------------------------------------------------------------
438→
439→function buildIntelligenceMetadata(injectionResult: InjectionResult) {
440→  return {
441→    brain_context_injected: injectionResult.injected,
442→    brain_context_decisions: injectionResult.decisionsCount,
443→    brain_context_learnings: injectionResult.learningsCount,
444→    brain_context_observations: injectionResult.observationsCount,
445→    brain_context_tokens_est: injectionResult.tokensEstimated,
446→  };
447→}
