 373→/**
 374→ * Seed an LLM trace directly for testing dashboard/audit scenarios
 375→ * that need pre-existing trace data.
 376→ */
 377→export async function seedLlmTrace(
 378→  surreal: Surreal,
 379→  traceId: string,
 380→  options: {
 381→    model: string;
 382→    input_tokens: number;
 383→    output_tokens: number;
 384→    cost_usd: number;
 385→    latency_ms: number;
 386→    workspaceId: string;
 387→    taskId?: string;
 388→    sessionId?: string;
 389→    stop_reason?: string;
 390→    cache_read_tokens?: number;
 391→    cache_creation_tokens?: number;
 392→    created_at?: Date;
 393→  },
 394→): Promise<string> {
 395→  const traceRecord = new RecordId("trace", traceId);
 396→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
 397→
 398→  // Ensure a test identity exists for the actor field (required by trace schema)
 399→  const actorId = `proxy-test-actor-${options.workspaceId}`;
 400→  const actorRecord = new RecordId("identity", actorId);
 401→  await surreal.query(
 402→    `CREATE $actor CONTENT { name: "proxy-test-system", type: "system", workspace: $ws, created_at: time::now() };`,
 403→    { actor: actorRecord, ws: workspaceRecord },
 404→  ).catch(() => undefined); // Ignore if already exists
 405→
 406→  const traceContent: Record<string, unknown> = {
 407→    type: "llm_call",
 408→    model: options.model,
 409→    input_tokens: options.input_tokens,
 410→    output_tokens: options.output_tokens,
 411→    cache_read_tokens: options.cache_read_tokens ?? 0,
 412→    cache_creation_tokens: options.cache_creation_tokens ?? 0,
 413→    cost_usd: options.cost_usd,
 414→    latency_ms: options.latency_ms,
 415→    stop_reason: options.stop_reason ?? "end_turn",
 416→    workspace: workspaceRecord,
 417→    actor: actorRecord,
 418→    created_at: options.created_at ?? new Date(),
 419→  };
 420→
 421→  // Link session directly on trace record (schema: session TYPE option<record<agent_session>>)
 422→  if (options.sessionId) {
 423→    traceContent.session = new RecordId("agent_session", options.sessionId);
 424→  }
 425→
 426→  await surreal.query(`CREATE $trace CONTENT $content;`, {
 427→    trace: traceRecord,
 428→    content: traceContent,
 429→  });
 430→
 431→  // Create workspace edge
 432→  await surreal.query(
 433→    `RELATE $trace->scoped_to->$workspace SET created_at = time::now();`,
 434→    { trace: traceRecord, workspace: workspaceRecord },
 435→  );
 436→
 437→  // Create task edge if provided
 438→  if (options.taskId) {
 439→    const taskRecord = new RecordId("task", options.taskId);
 440→    await surreal.query(
 441→      `RELATE $trace->attributed_to->$task SET created_at = time::now();`,
 442→      { trace: traceRecord, task: taskRecord },
 443→    );
 444→  }
 445→
 446→  // Create session edge if provided
 447→  if (options.sessionId) {
 448→    const sessionRecord = new RecordId("agent_session", options.sessionId);
 449→    await surreal.query(
 450→      `RELATE $sess->invoked->$trace SET created_at = time::now();`,
 451→      { trace: traceRecord, sess: sessionRecord },
 452→    );
 453→  }
 454→
 455→  return traceId;
 456→}
