 920→  );
 921→
 922→  return (results[0] ?? []) as ObservationRecord[];
 923→}
 924→
 925→// ---------------------------------------------------------------------------
 926→// Intelligence: Extended Proxy Request Options
 927→// ---------------------------------------------------------------------------
 928→
 929→/**
 930→ * Send a proxy request with additional intelligence-related headers.
 931→ * Extends the base sendProxyRequest with session and session-end headers.
 932→ */
 933→export async function sendProxyRequestWithIntelligence(
 934→  baseUrl: string,
 935→  options: ProxyRequestOptions & {
 936→    sessionHeader?: string;
 937→    sessionEndHeader?: boolean;
 938→    systemPrompt?: string | Array<{ type: string; text: string; cache_control?: { type: string } }>;
 939→  },
 940→): Promise<Response> {
 941→  const body = JSON.parse(buildProxyRequestBody(options));
 942→
 943→  // Add system prompt if provided (for context injection tests)
 944→  if (options.systemPrompt) {
 945→    body.system = options.systemPrompt;
 946→  }
 947→
 948→  const headers = buildProxyHeaders(options);
 949→
 950→  if (options.sessionHeader) {
 951→    headers["X-Brain-Session"] = options.sessionHeader;
 952→  }
 953→  if (options.sessionEndHeader) {
 954→    headers["X-Brain-Session-End"] = "true";
 955→  }
 956→
 957→  return fetch(`${baseUrl}/proxy/llm/anthropic/v1/messages`, {
 958→    method: "POST",
 959→    headers,
 960→    body: JSON.stringify(body),
 961→  });
 962→}
 963→
 964→// ---------------------------------------------------------------------------
 965→// Intelligence: Conversation Query Helpers
 966→// ---------------------------------------------------------------------------
 967→
 968→export type ConversationRecord = {
 969→  id: RecordId;
 970→  workspace: RecordId;
 971→  title: string;
 972→  source?: string;
 973→  createdAt: Date;
 974→  updatedAt: Date;
 975→};
 976→
 977→/**
 978→ * Query conversations for a workspace, optionally filtered by source.
 979→ */
 980→export async function getConversationsForWorkspace(
 981→  surreal: Surreal,
 982→  workspaceId: string,
 983→  options?: { source?: string },
 984→): Promise<ConversationRecord[]> {
 985→  const workspaceRecord = new RecordId("workspace", workspaceId);
 986→
 987→  const sourceFilter = options?.source
 988→    ? `AND source = $source`
 989→    : "";
 990→
 991→  const results = await surreal.query(
 992→    `SELECT * FROM conversation WHERE workspace = $ws ${sourceFilter} ORDER BY createdAt DESC;`,
 993→    { ws: workspaceRecord, source: options?.source },
 994→  );
 995→
 996→  return (results[0] ?? []) as ConversationRecord[];
 997→}
 998→
 999→/**
1000→ * Get traces linked to a specific conversation.
1001→ */
1002→export async function getTracesForConversation(
1003→  surreal: Surreal,
1004→  conversationId: string,
1005→): Promise<LlmTraceRecord[]> {
1006→  const conversationRecord = new RecordId("conversation", conversationId);
1007→
1008→  const results = await surreal.query(
1009→    `SELECT * FROM trace WHERE input.conversation = $conv ORDER BY created_at DESC;`,
1010→    { conv: conversationRecord },
1011→  );
1012→
1013→  return (results[0] ?? []) as LlmTraceRecord[];
1014→}
1015→
1016→// ---------------------------------------------------------------------------
1017→// Intelligence: Completed Task Helpers
1018→// ---------------------------------------------------------------------------
1019→
1020→/**
1021→ * Seed a completed task with no decision links for reverse coherence testing.
1022→ * Uses created_at for the age threshold (task schema has no completed_at field).
1023→ */
1024→export async function seedCompletedTaskWithoutDecision(
1025→  surreal: Surreal,
1026→  taskId: string,
1027→  options: {
1028→    workspaceId: string;
1029→    title: string;
1030→    completedAt?: Date;
1031→  },
1032→): Promise<string> {
1033→  const taskRecord = new RecordId("task", taskId);
1034→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
1035→  const createdAt = options.completedAt
1036→    ? new Date(options.completedAt.getTime() - 7 * 24 * 60 * 60 * 1000)
1037→    : new Date(Date.now() - 22 * 24 * 60 * 60 * 1000);
1038→
1039→  await surreal.query(`CREATE $task CONTENT $content;`, {
1040→    task: taskRecord,
1041→    content: {
1042→      title: options.title,
1043→      status: "completed",
