1071→
1072→// ---------------------------------------------------------------------------
1073→// Intelligence: Trace Content Helpers
1074→// ---------------------------------------------------------------------------
1075→
1076→/**
1077→ * Seed an LLM trace with response content in the FLEXIBLE output field.
1078→ * Used for Observer per-trace analysis testing.
1079→ */
1080→export async function seedLlmTraceWithContent(
1081→  surreal: Surreal,
1082→  traceId: string,
1083→  options: {
1084→    model: string;
1085→    workspaceId: string;
1086→    sessionId?: string;
1087→    conversationId?: string;
